3_real_world_example.code:
const rawInput = ['javascript', 'html', 'css', 'html', 'javascript'];

// 1. Pass the messy array into a new Set to instantly destroy duplicates
const uniqueSet = new Set(rawInput);

// 2. Convert the Set back into a standard Array using the Spread operator
const cleanArray = [...uniqueSet];

console.log(cleanArray); // ['javascript', 'html', 'css']

// Super-fast lookup:
if (uniqueSet.has('css')) {
  console.log('CSS is definitely in there.');
}

